// Pieces de la maison
const pieces = ['salon', 'cuisine', 'chambre', 'entree'];
const types = ['temperature', 'humidite', 'mouvement', 'fumee'];

// Choix aleatoire
const piece = pieces[Math.floor(Math.random() * pieces.length)];
const type = types[Math.floor(Math.random() * types.length)];

// Generation de la valeur
let valeur;
if (type === 'temperature') {
    valeur = Math.random() < 0.05 ? 999 : Math.round((Math.random() * 25 + 15) * 10) / 10;
} else if (type === 'humidite') {
    valeur = Math.round((Math.random() * 50 + 30) * 10) / 10;
} else if (type === 'mouvement') {
    valeur = Math.random() < 0.5;
} else if (type === 'fumee') {
    valeur = Math.random() < 0.05 ? Math.round((Math.random() * 5 + 95) * 10) / 10 : Math.round(Math.random() * 100 * 10) / 10;
}

// Construire le message
msg.topic = `maison/${piece}/${type}`;
msg.payload = JSON.stringify({
    sensor: type,
    value: valeur,
    room: piece,
    timestamp: new Date().toISOString()
});

return msg;

let donnees;
try {
    donnees = JSON.parse(msg.payload);
} catch(e) {
    msg.payload = '[INVALIDE] Message non-JSON';
    return [null, msg];
}

const type = donnees.sensor;
const valeur = donnees.value;
const piece = donnees.room;

// Plages valides
const plages = {
    temperature: { min: -20, max: 60 },
    humidite: { min: 0, max: 100 },
    fumee: { min: 0, max: 100 }
};

let valide = false;
let raison = '';

if (type === 'mouvement') {
    valide = typeof valeur === 'boolean';
    if (!valide) raison = 'doit etre un booleen';
} else if (plages[type]) {
    valide = valeur >= plages[type].min && valeur <= plages[type].max;
    if (!valide) raison = `hors plage ${plages[type].min} a ${plages[type].max}`;
} else {
    raison = 'type inconnu';
}

if (valide) {
    // Sortie 1 : message valide, garder le routing key
    msg.routingKey = msg.topic ? msg.topic.replace(/\//g, '.') : '';
    msg.payload = JSON.stringify(donnees);
    return [msg, null];
} else {
    // Sortie 2 : message invalide
    msg.payload = `[INVALIDE] ${type} ${piece}: ${valeur} (${raison})`;
    return [null, msg];
}

let donnees;
try {
    donnees = JSON.parse(msg.payload);
} catch(e) {
    return null;
}

const type = donnees.sensor;
const valeur = donnees.value;
const piece = donnees.room || 'inconnue';

let niveau = null;
let texte = '';

if (type === 'temperature') {
    if (valeur > 50) { niveau = 'CRITICAL'; texte = `Temperature ${piece}: ${valeur}°C`; }
    else if (valeur > 35) { niveau = 'WARNING'; texte = `Temperature ${piece}: ${valeur}°C`; }
} else if (type === 'fumee') {
    if (valeur > 70) { niveau = 'CRITICAL'; texte = `Fumee ${piece}: ${valeur}/100`; }
    else if (valeur > 40) { niveau = 'WARNING'; texte = `Fumee ${piece}: ${valeur}/100`; }
} else if (type === 'mouvement') {
    if (valeur === true) { niveau = 'INFO'; texte = `Mouvement detecte: ${piece}`; }
}

if (niveau) {
    const pad = niveau === 'CRITICAL' ? '' : niveau === 'WARNING' ? ' ' : '    ';
    msg.payload = `[${niveau}]${pad} ${texte}`;
    return msg;
}

return null;
